
(function($){
	var wrap, next;
	function show() {
		var parent = $('#wp-auth-check'),
			form = $('#wp-auth-check-form'),
			noframe = wrap.find('.wp-auth-fallback-expired'),
			frame, loaded = false;
		if ( form.length ) {
			$(window).on( 'beforeunload.wp-auth-check', function(e) {
				e.originalEvent.returnValue = window.authcheckL10n.beforeunload;
			});
			frame = $('<iframe id="wp-auth-check-frame" frameborder="0">').attr( 'title', noframe.text() );
			frame.on( 'load', function() {
				var height, body;
				loaded = true;
				form.removeClass( 'loading' );
				try {
					body = $(this).contents().find('body');
					height = body.height();
				} catch(e) {
					wrap.addClass('fallback');
					parent.css( 'max-height', '' );
					form.remove();
					noframe.focus();
					return;
				}
				if ( height ) {
					if ( body && body.hasClass('interim-login-success') )
						hide();
					else
						parent.css( 'max-height', height + 40 + 'px' );
				} else if ( ! body || ! body.length ) {
					wrap.addClass('fallback');
					parent.css( 'max-height', '' );
					form.remove();
					noframe.focus();
				}
			}).attr( 'src', form.data('src') );
			form.append( frame );
		}
		$( 'body' ).addClass( 'modal-open' );
		wrap.removeClass('hidden');
		if ( frame ) {
			frame.focus();
			setTimeout( function() {
				if ( ! loaded ) {
					wrap.addClass('fallback');
					form.remove();
					noframe.focus();
				}
			}, 10000 );
		} else {
			noframe.focus();
		}
	}
	function hide() {
		$(window).off( 'beforeunload.wp-auth-check' );
		if ( typeof adminpage !== 'undefined' && ( adminpage === 'post-php' || adminpage === 'post-new-php' ) &&
			typeof wp !== 'undefined' && wp.heartbeat ) {
			$(document).off( 'heartbeat-tick.wp-auth-check' );
			wp.heartbeat.connectNow();
		}
		wrap.fadeOut( 200, function() {
			wrap.addClass('hidden').css('display', '');
			$('#wp-auth-check-frame').remove();
			$( 'body' ).removeClass( 'modal-open' );
		});
	}
	function schedule() {
		var interval = parseInt( window.authcheckL10n.interval, 10 ) || 180; 
		next = ( new Date() ).getTime() + ( interval * 1000 );
	}
}(jQuery));
